import React, { useState} from 'react'
import {useNavigate} from 'react-router-dom';
import './login.css';




function Login(props) {

  const [email, setEmail] = useState("");
  const [pass, setPass] = useState("");

  const navigate = useNavigate();

  // const HandleClick=()=>{
  //   navigate("/SignUp");
  // }



  const handleSubmit=(event)=>{

    event.preventDefault();

    props.contextValue.signInWithEmailAndPassword(props.contextValue.auth, email, pass)
    .then(()=>{
      alert( "Logged in!" )
      navigate("/AfterLogin")
    }).catch((error)=>{
      const errorCode = error.code;
      const errorMessage = error.message;
      alert("Error: "+ errorCode + " - " + errorMessage);
    })
  }

  

  



  return (
    <div>
    {/* <div className='nav'>
      <p><h1>VP</h1><h3>Vicharan Prsaryantu</h3></p>
      <button onClick={HandleClick} id="btn">SignUp</button>
    </div> */}

    {/* <div>
      <BrowserRouter>
      <Routes  >
          <Route path="/" element={<AfterLogin />} />
        </Routes>
      </BrowserRouter>
    </div> */}

    <div className='Form' style={{height: "200px"}}>
      <form >
        <label htmlFor='inp1'>Email: &nbsp; &nbsp; &nbsp; &nbsp;</label>
        <input type='email' value={email} id="inp1" onChange={((e)=>setEmail(e.target.value))} />
        <br></br>
        <label htmlFor='inp2'>Password: &nbsp;</label>
        <input type='password' id='inp2' value={pass} onChange={((e)=>setPass(e.target.value))} />
        <br></br><br></br>
        <button onClick={handleSubmit}>Submit</button>
        
        
      </form>
    </div>

    </div>
  )
}

export default Login
